import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.config.oauth2.client.CommonOAuth2Provider;
import org.springframework.security.oauth2.client.registration.ClientRegistration;
import org.springframework.security.oauth2.client.registration.ClientRegistrationRepository;
import org.springframework.security.oauth2.client.web.DefaultOAuth2UserService;
import org.springframework.security.oauth2.client.web.OAuth2LoginAuthenticationFilter;
import org.springframework.security.oauth2.core.user.OAuth2User;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.security.oauth2.jwt.JwtDecoder;
import org.springframework.security.oauth2.jwt.NimbusJwtDecoderJwkSupport;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

@SpringBootApplication
public class OpenIDConnectApplication {
    public static void main(String[] args) {
        SpringApplication.run(OpenIDConnectApplication.class, args);
    }

    @EnableWebSecurity
    public static class SecurityConfig extends WebSecurityConfigurerAdapter {
        @Override
        protected void configure(HttpSecurity http) throws Exception {
            http
                .authorizeRequests()
                    .antMatchers("/").permitAll()
                    .anyRequest().authenticated()
                .and()
                    .oauth2Login();
        }

        @Bean
        public ClientRegistrationRepository clientRegistrationRepository() {
            return new InMemoryClientRegistrationRepository(this.googleClientRegistration());
        }

        private ClientRegistration googleClientRegistration() {
            return CommonOAuth2Provider.GOOGLE.getBuilder("google")
                .clientId("YOUR_CLIENT_ID")
                .clientSecret("YOUR_CLIENT_SECRET")
                .build();
        }

        @Bean
        protected JwtDecoder jwtDecoder() {
            return new NimbusJwtDecoderJwkSupport("https://provider.com/oauth2/v3/certs");
        }

        @Bean
        public DefaultOAuth2UserService oauth2UserService() {
            return new DefaultOAuth2UserService() {
                @Override
                public OAuth2User loadUser(OAuth2UserRequest userRequest) throws OAuth2AuthenticationException {
                    OAuth2User oauth2User = super.loadUser(userRequest);
                    OAuth2UserAuthority authority = new OAuth2UserAuthority(oauth2User.getAttributes());
                    Map<String, Object> userAttributes = authority.getAttributes();
                    return new DefaultOidcUser(
                            Collections.singletonList(authority), userAttributes
                    );
                }
            };
        }
    }

    @RestController
    public class UserController {
        @GetMapping("/")
        public String home() {
            return "Welcome to the home page!";
        }

        @GetMapping("/user")
        public String user(@AuthenticationPrincipal OidcUser principal) {
            if (principal != null) {
                return "User Email: " + principal.getEmail();
            }
            return "Not authenticated";
        }
    }
}